SELECT
    c.*,
    u.real_name as sales_name
FROM tb_customer c
LEFT JOIN sys_user u ON c.sales_id = u.id


        c.is_deleted = #{query.isDeleted}


        c.is_deleted = 0


        AND c.real_name LIKE CONCAT('%', #{query.realName}, '%')


        AND c.phone LIKE CONCAT('%', #{query.phone}, '%')


        AND c.intention_level = #{query.intentionLevel}


        AND c.source = #{query.source}


        AND c.sales_id = #{query.salesId}


        AND c.create_time >= #{query.createTimeBegin}


        AND c.create_time <= CONCAT(#{query.createTimeEnd}, ' 23:59:59')


        AND c.sales_id IS NULL


ORDER BY c.create_time DESC
